import{_ as t,c as e,o as r,a2 as o}from"./chunks/framework.C94oF1kp.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"book/overview.md","filePath":"book/overview.md"}'),a={name:"book/overview.md"},d=o('<blockquote> “What I cannot create, I do not understand.” — Richard Feynman </blockquote><p>This little book contains a series of projects based on <a href="https://github.com/yhzhang0128/egos-2000" target="_blank"> egos-2000</a>. The mission is to help students gain experience and confidence in creating their own operating system or similar computer systems in their future career.</p><h3 id="core-projects" tabindex="-1">Core projects <a class="header-anchor" href="#core-projects" aria-label="Permalink to &quot;Core projects&quot;">​</a></h3><p>There are 6 <strong>core projects</strong> covering most of the OS concepts for an undergraduate-level OS course (e.g., Cornell CS4411). The projects <strong>introduce the architectural support for OS one-by-one</strong>, which Cornell students found very helpful. For example, students would implement a preemptive scheduler without any knowledge of privilege levels.</p><table tabindex="0"><thead><tr><th></th><th>OS concepts</th><th>Architectural support</th></tr></thead><tbody><tr><td>Hello, World!</td><td>code, data, heap, stack</td><td>user-level ISA</td></tr><tr><td>Cooperative Threads</td><td>thread, yield, context switch</td><td></td></tr><tr><td>Preemptive Scheduler</td><td>interrupt and exception handling</td><td>control register, timer</td></tr><tr><td>System Call &amp; Privilege</td><td>inter-process communication</td><td>privilege level</td></tr><tr><td>Virtual Memory</td><td>virtual address space</td><td>page table translation</td></tr><tr><td>File System</td><td>block, inode, file, directory</td><td></td></tr></tbody></table><h3 id="advanced-projects" tabindex="-1">Advanced projects <a class="header-anchor" href="#advanced-projects" aria-label="Permalink to &quot;Advanced projects&quot;">​</a></h3><p>There are 3 <strong>advanced projects</strong> for a master-level course (e.g., Cornell CS5411).</p><table tabindex="0"><thead><tr><th></th><th>OS concepts</th><th>Architectural support</th></tr></thead><tbody><tr><td>SD Card Driver</td><td>synchronous I/O</td><td>bus, memory-mapped I/O</td></tr><tr><td>Ethernet &amp; TCP/IP</td><td>asynchronous I/O</td><td>platform-level interrupt controller</td></tr><tr><td>Multicore &amp; Spinlock</td><td>boot loader, mutex</td><td>atomic memory operation</td></tr></tbody></table><p>All the projects can run on the QEMU emulator as well as RISC-V boards. Now, let&#39;s get our hands dirty and have fun!</p>',9),n=[d];function s(c,i,l,p,h,u){return r(),e("div",null,n)}const b=t(a,[["render",s]]);export{v as __pageData,b as default};
